const login = async () => {
  if (!email || !password) {
    alert("Please enter both email and password.");
    return;
  }

  try {
    await signInWithEmailAndPassword(auth, email, password);
  } catch (err) {
    if (
      err.code === "auth/invalid-credential" ||
      err.code === "auth/user-not-found" ||
      err.code === "auth/wrong-password"
    ) {
      // Show a helpful dialog explaining what happened
      const wantsGoogle = window.confirm(
        "⚠️ Could not log in with email and password.\n\n" +
        "If you signed up with Google, you need to use the 'Continue with Google' button.\n\n" +
        "Click OK to sign in with Google now.\n" +
        "Click Cancel if you want to try a different password or reset it."
      );

      if (wantsGoogle) {
        try {
          const provider = new GoogleAuthProvider();
          const result = await signInWithPopup(auth, provider);

          // After Google sign in, link email/password so they can use both next time
          if (password && password.length >= 6) {
            try {
              const credential = EmailAuthProvider.credential(email, password);
              await linkWithCredential(result.user, credential);
              alert("✅ Signed in! Email/password login has been added to your account. You can now use either method to log in in the future.");
            } catch (linkErr) {
              // Link failed but they're still logged in with Google — that's fine
              if (linkErr.code !== "auth/provider-already-linked") {
                // Password too weak or other issue — just log them in with Google silently
              }
            }
          } else {
            alert("✅ Signed in with Google! Your password was too short to link (min 6 characters). Go to Settings → 'Add email/password login' to set a longer password.");
          }
        } catch (googleErr) {
          if (googleErr.code !== "auth/popup-closed-by-user") {
            alert("Google sign-in failed. Please try again.");
          }
        }
      }
      // If Cancel — do nothing, let them try again or use forgot password
    } else if (err.code === "auth/too-many-requests") {
      alert("Too many failed attempts. Please wait a few minutes before trying again, or use 'Forgot password' to reset it.");
    } else {
      alert(err.message);
    }
  }
};

