function ReportBugPage({
  user,
  accent,
  setActivePage,
}) {
  const [bugText, setBugText] =
    useState("");

  const submitBug = async () => {
    if (!bugText.trim()) {
      alert(
        "Please describe the issue."
      );
      return;
    }

    try {
      await setDoc(
        doc(
          db,
          "bugReports",
          Date.now().toString()
        ),
        {
          email: user.email,
          message: bugText,
          createdAt:
            new Date().toISOString(),
        }
      );

      alert(
        "Bug report submitted successfully ✅"
      );

      setBugText("");

      setActivePage("settings");
    } catch (err) {
      console.log(err);

      alert(
        "Failed to submit bug report."
      );
    }
  };

  return (
    <Card title="🐞 Report Bug">
      <p style={styles.muted}>
        Describe the issue you found
        in LIVORA.
      </p>

      <textarea
        style={styles.textArea}
        placeholder="Explain the bug..."
        value={bugText}
        onChange={(e) =>
          setBugText(e.target.value)
        }
      />

      <button
        style={{
          ...styles.primaryButton,
          background: accent,
        }}
        onClick={submitBug}
      >
        Submit Bug Report
      </button>
    </Card>
  );
}
